"use client";

import React from 'react';
import { GlobalControls } from './ui/GlobalControls';
import { GlyphPreview } from './ui/GlyphPreview';
import { PieceControls } from './ui/PieceControls';
import { Toolbar } from './ui/Toolbar';
import { Button } from '@/components/ui/button';
import { Download, Terminal } from 'lucide-react';
import { useGlyphStore } from './store/useGlyphStore';
import { generateSvgBlob } from './core/export';

export function GlyphEditorPage() {
    const { spec } = useGlyphStore();

    const handleExport = () => {
        const blob = generateSvgBlob(spec);
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `k3rn-glyph-${spec.global.character || 'K'}.svg`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
    };

    return (
        <div className="min-h-screen bg-bg-primary text-text-primary flex flex-col font-sans selection:bg-accent-primary selection:text-black">
            {/* Header - Strict, Bordered, No Blur */}
            <header className="h-16 border-b border-surface-2 px-6 flex items-center justify-between bg-bg-primary shrink-0">
                <div className="flex items-center gap-3">
                    <div className="w-4 h-4 bg-accent-primary" /> {/* Symbolic Accent */}
                    <h1 className="text-sm font-mono font-medium tracking-widest uppercase text-text-secondary">
                        K3RN.LABS <span className="text-text-primary">/// GLYPH EDITOR_v2</span>
                    </h1>
                </div>
                <div className="flex items-center gap-4">
                    <div className="hidden md:flex items-center gap-2 text-[10px] font-mono text-text-muted">
                        <Terminal size={12} />
                        <span>CANONICAL_MODE::ACTIVE</span>
                    </div>
                    <Button
                        onClick={handleExport}
                        className="bg-surface-1 hover:bg-accent-primary hover:text-black text-text-primary border border-surface-2 rounded-none h-9 px-4 text-xs font-mono uppercase tracking-wider transition-colors"
                    >
                        <Download size={14} className="mr-2" />
                        Export_SVG
                    </Button>
                </div>
            </header>

            <main className="flex-1 grid grid-cols-1 lg:grid-cols-12 overflow-hidden">
                {/* Left: Controls - Scrollable */}
                <div className="lg:col-span-4 border-r border-surface-2 overflow-y-auto bg-bg-primary">
                    <div className="p-0 space-y-0 divide-y divide-surface-2">
                        <div className="p-6">
                            <GlobalControls />
                        </div>
                        <div className="p-6">
                            <PieceControls />
                        </div>
                    </div>
                </div>

                {/* Right: Preview - Centered, Technical Background */}
                <div className="lg:col-span-8 bg-bg-primary relative flex flex-col">
                    {/* Workspace Header */}
                    <div className="absolute top-0 left-0 right-0 h-10 border-b border-surface-2 flex items-center px-4 justify-between pointer-events-none z-10">
                        <span className="text-[10px] font-mono text-text-muted">VIEWPORT::{spec.canvas.size}PX</span>
                        <span className="text-[10px] font-mono text-text-muted">GRID::ON</span>
                    </div>

                    {/* Canvas Area */}
                    <div className="flex-1 flex items-center justify-center relative bg-[radial-gradient(#222_1px,transparent_1px)] [background-size:16px_16px]">
                        <div className="relative">
                            <GlyphPreview className="w-[500px] h-[500px]" />
                            <Toolbar />
                        </div>
                    </div>

                    {/* Footer Info */}
                    <div className="h-8 border-t border-surface-2 flex items-center px-4 justify-end">
                        <p className="text-[10px] text-text-muted font-mono uppercase">
                            Select parts to edit • Drag to rotate
                        </p>
                    </div>
                </div>
            </main>
        </div>
    );
}
